} from "../src/index.js";

describe("Switchyard contracts", () => {
  it("parses a runtime-backed run", () => {
    const run = runSchema.parse({
      id: "run_123",
      runtime: "opencode",
      provider: "opencode",
      model: "opencode/big-pickle",
      adapterType: "acpx",
      cwd: "/repo",
      task: "Inspect the repo",
      status: "queued",
      placement: "local",
      approvalPolicy: "default",
      timeoutSeconds: 600,
      metadata: {},
      createdAt: "2026-05-11T00:00:00.000Z"
    });

    expect(run.status).toBe("queued");
    expect(run.adapterType).toBe("acpx");
  });

  it("requires run ids to use the expected prefix", () => {
    expect(() =>
      runSchema.parse({
        id: "bad_123",
        runtime: "opencode",
        provider: "opencode",
        model: "opencode/big-pickle",
        adapterType: "acpx",
        cwd: "/repo",
        task: "Inspect the repo",
        status: "queued",
        placement: "local",
        approvalPolicy: "default",
        timeoutSeconds: 600,
        metadata: {},
        createdAt: "2026-05-11T00:00:00.000Z"
      })
    ).toThrow();
  });

  it("parses runtime session metadata", () => {
    const session = runtimeSessionSchema.parse({
      id: "session_123",
      runId: "run_123",
      runtime: "opencode",
      provider: "opencode",
      model: "opencode/big-pickle",
      protocol: "acpx",
      status: "active",
      externalSessionKey: "ses_abc",
      processId: 12345,
      state: {},
      createdAt: "2026-05-11T00:00:00.000Z"
